inputs.script:
const normalize=(value)=>(value||'').replace(/\s+/g,' ').trim();
const sleep=(ms)=>new Promise((resolve)=>setTimeout(resolve,ms));
const isVisible=(node)=>{if(!(node instanceof Element)) return false; const rect=node.getBoundingClientRect(); if(!rect||rect.width<=0||rect.height<=0) return false; const style=getComputedStyle(node); return style.display!=='none'&&style.visibility!=='hidden'&&style.opacity!=='0';};
const isClickable=(node)=>node instanceof HTMLAnchorElement||node instanceof HTMLButtonElement||node.getAttribute('role')==='button'||typeof node.onclick==='function';
const findClickableAncestor=(node)=>{let current=node; for(let depth=0; current&&depth<8; depth++, current=current.parentElement){ if(isVisible(current)&&isClickable(current)) return current; } return null;};
const toAbsoluteUrl=(value)=>{try{return new URL(value,location.origin).toString();}catch{return '';}};
const normalizedPath=(value)=>{try{return new URL(value,location.origin).pathname.replace(/\/+/g,'/').replace(/\/?$/,'/').toLowerCase();}catch{return '';}};
const resolveHref=(node)=>{if(!(node instanceof Element)) return ''; if(node instanceof HTMLAnchorElement){ return normalize(node.getAttribute('href')||node.href||''); } const nested=node.querySelector('a[href]'); return nested instanceof HTMLAnchorElement ? normalize(nested.getAttribute('href')||nested.href||'') : ''; };
const handle='{handle}'.replace(/^@+/,'').trim().toLowerCase();
const expectedPath=`/${handle}/`;
const storyPath=`/stories/${handle}/`;
const input=document.querySelector("input[aria-label='Search input'], input[placeholder='Search']");
if(!(input instanceof HTMLInputElement)) throw new Error('Search input not found');
const valueSetter=Object.getOwnPropertyDescriptor(HTMLInputElement.prototype,'value')?.set;
if(!valueSetter) throw new Error('HTMLInputElement.value setter unavailable');
input.focus();
valueSetter.call(input,'');
input.dispatchEvent(new InputEvent('input',{bubbles:true,composed:true,data:null,inputType:'deleteContentBackward'}));
let current='';
for(const ch of handle){
  current += ch;
  input.dispatchEvent(new KeyboardEvent('keydown',{key:ch,bubbles:true}));
  valueSetter.call(input,current);
  input.dispatchEvent(new InputEvent('input',{bubbles:true,composed:true,data:ch,inputType:'insertText'}));
  input.dispatchEvent(new KeyboardEvent('keyup',{key:ch,bubbles:true}));
  await sleep(95);
}
input.dispatchEvent(new Event('change',{bubbles:true,composed:true}));
await sleep(2200);
const exactAnchors=Array.from(document.querySelectorAll('a[href]')).filter(isVisible).map((node)=>({node,href:toAbsoluteUrl(node.getAttribute('href')||node.href||''),path:normalizedPath(node.getAttribute('href')||node.href||''),label:normalize([node.textContent||'',node.getAttribute('aria-label')||''].join(' ')).toLowerCase(),rect:node.getBoundingClientRect()})).filter((entry)=>entry.path===expectedPath);
if(exactAnchors.length){
  exactAnchors.sort((a,b)=>a.rect.top-b.rect.top||a.rect.left-b.rect.left||(a.rect.width*a.rect.height)-(b.rect.width*b.rect.height)||a.label.length-b.label.length);
  const chosenAnchor=exactAnchors[0];
  chosenAnchor.node.click();
  return JSON.stringify({handle,status:'clicked_exact_profile_result',match_label:chosenAnchor.label,match_rect:{top:Math.round(chosenAnchor.rect.top),left:Math.round(chosenAnchor.rect.left),width:Math.round(chosenAnchor.rect.width),height:Math.round(chosenAnchor.rect.height)},navigate_to:chosenAnchor.href});
}
const candidates=Array.from(document.querySelectorAll('*')).filter(isVisible).map((node)=>{const clickable=findClickableAncestor(node); const href=resolveHref(clickable||node); return {node,clickable,label:normalize([node.textContent||'',node.getAttribute?.('aria-label')||''].join(' ')).toLowerCase(),rect:node.getBoundingClientRect(),href,path:normalizedPath(href)};}).filter((entry)=>entry.label.includes(handle)).filter((entry)=>entry.label.length<=120).filter((entry)=>entry.rect.left<window.innerWidth*0.6&&entry.rect.top<window.innerHeight*0.8).filter((entry)=>entry.rect.width<=420&&entry.rect.height<=140).filter((entry)=>entry.path!==''&&entry.path!==expectedPath?!entry.path.startsWith('/stories/'):true);
if(!candidates.length) return JSON.stringify({handle,status:'search_miss',url:location.href,input_value:input.value});
candidates.sort((a,b)=>(a.path===expectedPath?0:1)-(b.path===expectedPath?0:1)||(a.rect.width*a.rect.height)-(b.rect.width*b.rect.height)||a.rect.top-b.rect.top||a.rect.left-b.rect.left||a.label.length-b.label.length);
const chosen=candidates[0];
const clickable=chosen.clickable||findClickableAncestor(chosen.node);
if(!clickable) return JSON.stringify({handle,status:'search_match_not_clickable',match_label:chosen.label,match_rect:{top:Math.round(chosen.rect.top),left:Math.round(chosen.rect.left),width:Math.round(chosen.rect.width),height:Math.round(chosen.rect.height)},url:location.href,input_value:input.value});
const href=resolveHref(clickable);
if(href&&normalizedPath(href)!==storyPath){
  const absolute=toAbsoluteUrl(href);
  window.location.assign(absolute);
  return JSON.stringify({handle,status:'opened_result_via_href_fallback',match_label:chosen.label,match_rect:{top:Math.round(chosen.rect.top),left:Math.round(chosen.rect.left),width:Math.round(chosen.rect.width),height:Math.round(chosen.rect.height)},navigate_to:absolute});
}
clickable.click();
return JSON.stringify({handle,status:'opened_result_via_click',match_label:chosen.label,match_rect:{top:Math.round(chosen.rect.top),left:Math.round(chosen.rect.left),width:Math.round(chosen.rect.width),height:Math.round(chosen.rect.height)},clicked_tag:clickable.tagName,clicked_aria:normalize(clickable.getAttribute('aria-label')||''),url:location.href});

const normalize=(value)=>(value||'').replace(/\s+/g,' ').trim();
const sleep=(ms)=>new Promise((resolve)=>setTimeout(resolve,ms));
const textFor=(node)=>normalize(node?.innerText||node?.textContent||node?.getAttribute?.('aria-label')||'');
const isVisible=(node)=>{if(!(node instanceof Element)) return false; const rect=node.getBoundingClientRect(); if(!rect||rect.width<=0||rect.height<=0) return false; const style=window.getComputedStyle(node); return style.display!=='none'&&style.visibility!=='hidden'&&style.opacity!=='0';};
const normalizedPath=(value)=>{try{return new URL(value,location.origin).pathname.replace(/\/+/g,'/').replace(/\/?$/,'/').toLowerCase();}catch{return '';}};
const getRoot=()=>document.querySelector('header')||document.querySelector('main header')||document.querySelector('main')||document;
const collect=(root)=>Array.from((root||document).querySelectorAll('button,a[role="button"],div[role="button"]')).filter(isVisible).map((node)=>({node,text:textFor(node),rect:node.getBoundingClientRect()})).filter((entry)=>/follow|requested/i.test(entry.text)&&entry.rect.top<Math.max(window.innerHeight*0.75,500));
const clickNode=(node)=>{node.scrollIntoView({block:'center',inline:'center'}); try{node.focus?.({preventScroll:true});}catch{}; try{node.click();}catch{}; const types=['pointerdown','mousedown','pointerup','mouseup','click']; for(const type of types){ try{ const eventName=type.startsWith('pointer')&&typeof PointerEvent!=='undefined'?PointerEvent:MouseEvent; node.dispatchEvent(new eventName(type,{bubbles:true,cancelable:true,composed:true,view:window,button:0,buttons:1,pointerType:'mouse'})); }catch{} } return true;};
const dismissTransient=()=>{const nodes=Array.from(document.querySelectorAll('button,a[role="button"],div[role="button"]')).filter(isVisible); for (const node of nodes) { const text=textFor(node); const aria=normalize(node.getAttribute('aria-label')||''); if (/^(not now|close)$/i.test(text)||/^close$/i.test(aria)) { try { node.click(); return text||aria||'dismissed'; } catch {} } } return null;};
const expected='{handle}'.replace(/^@+/,'').trim().toLowerCase();
const pathParts=location.pathname.split('/').filter(Boolean);
if(pathParts[0]==='stories'&&pathParts[1]?.toLowerCase()===expected){
  const profileAnchor=Array.from(document.querySelectorAll('a[href]')).find((node)=>isVisible(node)&&normalizedPath(node.getAttribute('href')||node.href||'')===`/${expected}/`);
  if(profileAnchor){ profileAnchor.click(); await sleep(1800); }
}
const settledHandle=location.pathname.split('/').filter(Boolean)[0]||'';
if(settledHandle.toLowerCase()!==expected) return JSON.stringify({handle:expected,status:'wrong_profile_after_search',current_handle:settledHandle,url:location.href});
if(/login/i.test(document.title)||document.querySelector('input[name="username"],input[name="enc_password"]')) return JSON.stringify({handle:expected,status:'login_required',url:location.href});
const bodyText=normalize(document.body?.innerText||'');
if(/sorry, this page isn't available|user not found|page isn't available/i.test(bodyText)) return JSON.stringify({handle:expected,status:'not_found',url:location.href});
let candidates=collect(getRoot()); if(!candidates.length) candidates=collect(document);
if(!candidates.length){const dismissed=dismissTransient(); if(dismissed){await sleep(600); candidates=collect(getRoot()); if(!candidates.length) candidates=collect(document);}}
const following=candidates.find((entry)=>/^following$/i.test(entry.text)); if(following) return JSON.stringify({handle:expected,status:'already_following',button_text:following.text,url:location.href});
const requested=candidates.find((entry)=>/^requested$/i.test(entry.text)); if(requested) return JSON.stringify({handle:expected,status:'requested',button_text:requested.text,url:location.href});
const follow=candidates.find((entry)=>/^(follow|follow back)$/i.test(entry.text)); if(!follow) return JSON.stringify({handle:expected,status:'blocked',visible_buttons:candidates.map((entry)=>entry.text),url:location.href});
let clicked=false;
for(let attempt=0; attempt<3; attempt++){
  clicked=clickNode(follow.node)||clicked;
  await sleep(1400 + attempt*500);
  candidates=collect(getRoot()); if(!candidates.length) candidates=collect(document);
  const followingAfterAttempt=candidates.find((entry)=>/^following$/i.test(entry.text)); if(followingAfterAttempt) return JSON.stringify({handle:expected,status:'followed',clicked,button_text:followingAfterAttempt.text,url:location.href,attempt:attempt+1});
  const requestedAfterAttempt=candidates.find((entry)=>/^requested$/i.test(entry.text)); if(requestedAfterAttempt) return JSON.stringify({handle:expected,status:'requested',clicked,button_text:requestedAfterAttempt.text,url:location.href,attempt:attempt+1});
}
const followStill=candidates.find((entry)=>/^(follow|follow back)$/i.test(entry.text));
return JSON.stringify({handle:expected,status:followStill?'click_failed':'unknown_after_click',clicked,button_text:followStill?followStill.text:null,visible_buttons:candidates.map((entry)=>entry.text),url:location.href});
